#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int sum = 0, x;
        for (int i = 0; i < 5; ++i) {
            scanf("%d", &x);
            sum += x;
        }
        printf("%d\n", sum);
    }
    return 0;
}

